import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

const DanhSachNuChinh = z.enum([
  'Nukumizu Kazuko',
  'Yanami Anna',
  'Yakishio Lemon',
  'Komari Chika',
  'Shikiya Yumeko',
  'Basori Tiara',
  'Nukumizu Kaju',
  'Tsukinoki Koto',
  'Himemiya Karen',
  'Asagumo Chihaya',
  'Amanatsu Konami',
  'Konuki Sayo',
  'Hokobaru Hibari',
  'Gondo Asami',
]);

const SchemaTrangThaiNhanVat = z.object({
  HaoCam: z.coerce.number().describe('Mức độ hảo cảm với nhân vật chính, không giới hạn phạm vi').prefault(0),
  TrangPhuc: z.string().describe('Mô tả trang phục đang mặc hiện tại').prefault(''),
  PhanUngSinhLy: z.string().describe('Một câu mô tả phản ứng sinh lý trực diện nhất').prefault(''),
  CoMat: z.boolean().describe('Nhân vật hiện có mặt hay không').prefault(false),
});

export const Schema = z.object({
  ThongTinTheGioi: z.object({
    Ngay: z.string().prefault(''),
    ThoiGian: z.string().prefault(''),
    DiaDiem: z.string().prefault(''),
  }).prefault({}),
  DuLieuNhanVat: z.record(DanhSachNuChinh, SchemaTrangThaiNhanVat).describe('Dữ liệu trạng thái của tất cả nhân vật nữ').transform(val => {
    // Đảm bảo tất cả các nhân vật được thiết lập sẵn đều tồn tại trong bản ghi
    DanhSachNuChinh.options.forEach(name => {
      if (!val[name]) {
        val[name] = SchemaTrangThaiNhanVat.parse({});
      }
    });
    return val;
  }).prefault({}),
});

(() => {
  registerMvuSchema(Schema);
})

