<body>
    <div id="magazine-container" class="magazine-container">
        <div id="magazine-pages"></div>
        <button id="prev-btn" class="nav-btn" aria-label="Trang trước"><i class="fas fa-arrow-left"></i></button>
        <button id="next-btn" class="nav-btn" aria-label="Trang sau"><i class="fas fa-arrow-right"></i></button>
    </div>

    <script type="module">
    (function() {
        const container = document.getElementById('magazine-container');
        if (!container) return;

        const pagesContainer = document.getElementById('magazine-pages');
        const prevBtn = document.getElementById('prev-btn');
        const nextBtn = document.getElementById('next-btn');

        let characters = [];
        let worldInfo = {};
        let currentIndex = 0;
        let isAnimating = false;

        function loadData() {
            try {
                const allVars = getAllVariables();
                // Cập nhật key truy cập theo cấu trúc YAML tiếng Việt
                worldInfo = _.get(allVars, 'stat_data.ThongTinTheGioi', {});
                const charData = _.get(allVars, 'stat_data.DuLieuNhanVat', {});
                characters = Object.keys(charData)
                    .map(name => ({ name, ...charData[name] }))
                    .filter(char => char.CoMat === true); // Key: CoMat
                return characters.length > 0;
            } catch (error) {
                console.error("MVU Tải hoặc phân tích dữ liệu thất bại:", error);
                displayError("Lỗi khi tải dữ liệu nhân vật.");
                return false;
            }
        }

        function createPageElement(character, index, total, state) {
            const page = document.createElement('div');
            page.className = `page ${state}`;
            const engName = character.engName || 'UNKNOWN';
            const imageUrl = character.image || `https://placehold.co/400x600/ccc/333?text=${character.name.substring(0,2)}`;
            const pageNumHtml = `<div class="page-number">${String(index + 1).padStart(2, '0')} / ${String(total).padStart(2, '0')}</div>`;

            // Key truy cập dữ liệu đã được cập nhật sang tiếng Việt: HaoCam, Ngay, ThoiGian, DiaDiem, TrangPhuc, PhanUngSinhLy
            page.innerHTML = `
                <div class="page-content">
                    <div class="eng-name-block">${engName}</div>
                    <div class="char-name-block"><h2 class="char-name">${character.name}</h2></div>
                    <div class="char-image-container"><div class="char-image-bg" style="background-image: url('${imageUrl}');"></div></div>
                    <div class="short-info-block">
                        <div class="info-item"><div class="info-label">Affection</div><div class="info-value favor">${character.HaoCam || 'N/A'}</div></div>
                        <div class="info-item"><div class="info-label">Date</div><div class="info-value">${worldInfo.Ngay || '??/??'}</div></div>
                        <div class="info-item"><div class="info-label">Time</div><div class="info-value">${worldInfo.ThoiGian || '--:--'}</div></div>
                        <div class="info-item"><div class="info-label">Location</div><div class="info-value">${worldInfo.DiaDiem || 'Không rõ'}</div></div>
                    </div>
                    <div class="long-text-block">
                        <div class="text-section"><h3 class="text-label"><i class="fas fa-tshirt"></i>Attire</h3><p class="text-content">${character.TrangPhuc || '<i>Chưa có mô tả</i>'}</p></div>
                        <div class="text-section"><h3 class="text-label"><i class="fas fa-heart-pulse"></i>Condition</h3><p class="text-content">${character.PhanUngSinhLy || '<i>Không có phản ứng đặc biệt</i>'}</p></div>
                    </div>
                    ${pageNumHtml}
                </div>`;
            return page;
        }

        function transitionTo(newIndex, direction) {
            if (isAnimating || characters.length <= 1) return;
            isAnimating = true;
            prevBtn.disabled = true;
            nextBtn.disabled = true;

            const totalChars = characters.length;
            const nextCharIndex = (newIndex % totalChars + totalChars) % totalChars;

            const oldPage = pagesContainer.querySelector('.page.active');
            const newPage = createPageElement(characters[nextCharIndex], nextCharIndex, totalChars, direction === 'next' ? 'prepare-next' : 'prepare-prev');

            pagesContainer.appendChild(newPage);

            requestAnimationFrame(() => {
                const newContent = newPage.querySelector('.page-content');
                newContent.classList.add('animate-in');

                if(oldPage) {
                    oldPage.classList.remove('active');
                    oldPage.classList.add(direction === 'next' ? 'exit-to-left' : 'exit-to-right');
                }
                newPage.classList.remove('prepare-next', 'prepare-prev');
                newPage.classList.add('active');

            });

            currentIndex = nextCharIndex;

            setTimeout(() => {
                if (oldPage) {
                    oldPage.remove();
                }
                isAnimating = false;
                prevBtn.disabled = false;
                nextBtn.disabled = false;
            }, 800);
        }

        function displayError(message) {
            container.innerHTML = `<div class="error-state"><i class="fas fa-exclamation-triangle fa-2x"></i><p style="margin-top: 10px;">${message}</p></div>`;
            prevBtn.style.display = 'none';
            nextBtn.style.display = 'none';
        }

        function initialize() {
            if (!loadData()) {
                displayError("Hiện không có nhân vật nào có mặt.");
                return;
            }

            const initialPage = createPageElement(characters[currentIndex], currentIndex, characters.length, 'active');
            pagesContainer.appendChild(initialPage);

            setTimeout(() => {
                const content = initialPage.querySelector('.page-content');
                if (content) {
                    content.classList.add('animate-in');
                }
            }, 100);

            if (characters.length <= 1) {
                prevBtn.style.display = 'none';
                nextBtn.style.display = 'none';
            }
        }

        if (prevBtn && nextBtn) {
            prevBtn.addEventListener('click', () => transitionTo(currentIndex - 1, 'prev'));
            nextBtn.addEventListener('click', () => transitionTo(currentIndex + 1, 'next'));
        }

        initialize();

    })();
    </script>
</body>
</html>
